#include <stdio.h>
#include <stdbool.h>
#include <string.h>

#define MAX_PROCESSES 10
#define MAX_RESOURCES 5

/*
 * Deadlock Detection Algorithm for Multiple Resource Instances
 * Based on the algorithm from Operating System Concepts
 */

typedef struct {
 int allocation[MAX_PROCESSES][MAX_RESOURCES];
 int request[MAX_PROCESSES][MAX_RESOURCES];
 int available[MAX_RESOURCES];
 int num_processes;
 int num_resources;
} SystemState;

// Function to compare if request <= work (element-wise)
bool canSatisfyRequest(int request[], int work[], int num_resources) {
 for (int j = 0; j < num_resources; j++) {
 if (request[j] > work[j]) {
 return false;
 }
 }
 return true;
}

// Function to add allocation to work (simulate resource release)
void addAllocation(int work[], int allocation[], int num_resources) {
 for (int j = 0; j < num_resources; j++) {
 work[j] += allocation[j];
 }
}

/*
 * Deadlock Detection Algorithm
 * Returns: true if deadlock exists, false otherwise
 * Fills deadlocked array with indices of deadlocked processes
 */
bool detectDeadlock(SystemState *sys, int deadlocked[], int *deadlock_count) {
 int work[MAX_RESOURCES];
 bool finish[MAX_PROCESSES];

 // Step 1: Initialize Work = Available
 memcpy(work, sys->available, sizeof(int) * sys->num_resources);

 // Assume all processes are unfinished
 for (int i = 0; i < sys->num_processes; i++) {
 finish[i] = false;
 }

 // Step 2: Find processes that can complete
 bool changed = true;
 while (changed) {
 changed = false;

 for (int i = 0; i < sys->num_processes; i++) {
 if (!finish[i]) {
 // Check if Request[i] <= Work
 if (canSatisfyRequest(sys->request[i], work, sys->num_resources)) {
 // Process can complete - release its resources
 addAllocation(work, sys->allocation[i], sys->num_resources);
 finish[i] = true;
 changed = true;
 printf(" Process P%d can complete, Work = [%d, %d, %d]\n", 
 i, work[0], work[1], work[2]);
 }
 }
 }
 }

 // Step 3: Identify deadlocked processes
 *deadlock_count = 0;
 for (int i = 0; i < sys->num_processes; i++) {
 if (!finish[i]) {
 deadlocked[*deadlock_count] = i;
 (*deadlock_count)++;
 }
 }

 return *deadlock_count > 0;
}

// Function to print the system state
void printSystemState(SystemState *sys) {
 printf("\n=== System State ===\n");
 printf("Available Resources: [%d, %d, %d]\n", 
 sys->available[0], sys->available[1], sys->available[2]);

 printf("\nAllocation Matrix:\n");
 printf(" A B C\n");
 for (int i = 0; i < sys->num_processes; i++) {
 printf("P%d: %d %d %d\n", i, 
 sys->allocation[i][0], 
 sys->allocation[i][1], 
 sys->allocation[i][2]);
 }

 printf("\nRequest Matrix:\n");
 printf(" A B C\n");
 for (int i = 0; i < sys->num_processes; i++) {
 printf("P%d: %d %d %d\n", i, 
 sys->request[i][0], 
 sys->request[i][1], 
 sys->request[i][2]);
 }
}

// Process termination recovery - simple implementation
void recoverByTermination(SystemState *sys) {
 int deadlocked[MAX_PROCESSES];
 int deadlock_count;

 printf("\n=== Recovery by Process Termination ===\n");

 while (detectDeadlock(sys, deadlocked, &deadlock_count)) {
 printf("Deadlock detected! Processes: ");
 for (int i = 0; i < deadlock_count; i++) {
 printf("P%d ", deadlocked[i]);
 }
 printf("\n");

 // Terminate the first deadlocked process (simplest strategy)
 int victim = deadlocked[0];
 printf("Terminating process P%d to break deadlock...\n", victim);

 // Release all resources held by the terminated process
 for (int j = 0; j < sys->num_resources; j++) {
 sys->available[j] += sys->allocation[victim][j];
 sys->allocation[victim][j] = 0;
 sys->request[victim][j] = 0;
 }

 // Re-run detection
 printf("\nRe-checking for deadlock...\n");
 }

 printf("Deadlock resolved!\n");
}

int main() {
 SystemState sys;

 // Set up the example from the topic
 sys.num_processes = 4;
 sys.num_resources = 3;

 // Available: (0, 0, 0)
 sys.available[0] = 0;
 sys.available[1] = 0;
 sys.available[2] = 0;

 // Allocation Matrix
 int alloc[4][3] = {
 {0, 1, 0}, // P0
 {2, 0, 0}, // P1
 {3, 0, 3}, // P2
 {2, 1, 1} // P3
 };

 // Request Matrix
 int req[4][3] = {
 {0, 0, 0}, // P0
 {2, 0, 2}, // P1
 {0, 0, 0}, // P2
 {1, 0, 0} // P3
 };

 for (int i = 0; i < 4; i++) {
 for (int j = 0; j < 3; j++) {
 sys.allocation[i][j] = alloc[i][j];
 sys.request[i][j] = req[i][j];
 }
 }

 printf("========================================\n");
 printf(" DEADLOCK DETECTION ALGORITHM\n");
 printf("========================================\n");

 printSystemState(&sys);

 printf("\n=== Running Detection Algorithm ===\n");

 int deadlocked[MAX_PROCESSES];
 int deadlock_count;

 bool has_deadlock = detectDeadlock(&sys, deadlocked, &deadlock_count);

 printf("\n=== Detection Result ===\n");
 if (has_deadlock) {
 printf("DEADLOCK DETECTED!\n");
 printf("Deadlocked processes: ");
 for (int i = 0; i < deadlock_count; i++) {
 printf("P%d ", deadlocked[i]);
 }
 printf("\n");
 } else {
 printf("NO DEADLOCK DETECTED\n");
 printf("All processes can complete successfully.\n");
 }

 return 0;
}
